using namespace std;

string convertToBase(long long num, int base) {
    string res;
    while (num > 0) {
        int rem = num % base;
        char c;
        if (rem < 10) {
            c = '0' + rem;
        } else {
            c = 'A' + (rem - 10);
        }
        res = c + res;
        num = num / base;
    }
    return res;
}

string solve(long long n) {
    long long n2 = n * n;
    long long n3 = n2 * n;
    string hex_part = convertToBase(n2, 16);
    string base36_part = convertToBase(n3, 36);
