def convertToBase(num: Long, base: Int): String = {
    if (num == 0) "0"
    else {
        var remaining = num
        var result = ""
        while (remaining > 0) {
            val rem = remaining % base
            val c = if (rem < 10) (rem + '0'.toInt).toChar else ('A' + (rem - 10).toInt).toChar
            result = c.toString + result
            remaining = remaining / base
        }
        result
    }
}

def solve(n: Long): String = {
    val n2 = n * n
    val n3 = n2 * n
    val hexPart = convertToBase(n2, 16)
    val base36Part = convertToBase(n3, 36)
    hexPart + base36Part
}
```

